            for dy in (-1, 0, 1):
                nx, ny = sx + dx, sy + dy
                if not inside(nx, ny) or (nx, ny) in obstacles:
                    continue
                v = -(abs(nx - tx) + abs(ny - ty))
                if v > bestv or (v == bestv and (dx, dy) < (best[0], best[1])):
